import React from 'react';
import ParamHeader from './ParamHeader';

function SparkleToggle({ sparkle, onSparkleChange, paramIcons, onIconClick, buttonRefs }) {
  return (
    <div className="bg-white/60 backdrop-blur-sm rounded-2xl p-4 shadow-lg">
      <div className="flex items-center justify-between">
        <ParamHeader
          paramKey="sparkle"
          label="闪闪特效"
          iconColor="text-yellow-500"
          onIconClick={onIconClick}
          buttonRef={(el) => buttonRefs.current.sparkle = el}
        />
        <button
          onClick={() => onSparkleChange(!sparkle)}
          className={`w-14 h-7 rounded-full transition-all shadow-inner ${
            sparkle ? 'bg-gradient-to-r from-yellow-400 to-pink-400' : 'bg-gray-300'
          }`}
        >
          <div
            className={`w-6 h-6 bg-white rounded-full shadow-lg transition-transform ${
              sparkle ? 'translate-x-7' : 'translate-x-0.5'
            }`}
          />
        </button>
      </div>
    </div>
  );
}

export default SparkleToggle;
